    bodyJa:[ 'かつて賑わった祭りも、年々参加者が減る一方だった。', '伝統が途絶えるのを惜しみ、若者たちが立ち上がった。', '準備を重ねるにつれて、町の関心も少しずつ高まった。', '当日は世代を問わず、多くの人が広場に集まった。', '受け継がれた灯は、また次の世代へと手渡されていく。' ],
    bodyReadings:[ [ { text:'賑', reading:'にぎ' }, { text:'祭', reading:'まつ' }, { text:'年々', reading:'ねんねん' }, { text:'参加者', reading:'さんかしゃ' }, { text:'減', reading:'へ' } ], [ { text:'伝統', reading:'でんとう' }, { text:'途絶', reading:'とだ' }, { text:'惜', reading:'お' }, { text:'若者', reading:'わかもの' }, { text:'立', reading:'た' }, { text:'上', reading:'あ' } ], [ { text:'準備', reading:'じゅんび' }, { text:'重', reading:'かさ' }, { text:'町', reading:'まち' }, { text:'関心', reading:'かんしん' }, { text:'高', reading:'たか' } ], [ { text:'当日', reading:'とうじつ' }, { text:'世代', reading:'せだい' }, { text:'問', reading:'と' }, { text:'多', reading:'おお' }, { text:'広場', reading:'ひろば' }, { text:'集', reading:'あつ' } ], [ { text:'受', reading:'う' }, { text:'継', reading:'つ' }, { text:'灯', reading:'ひ' }, { text:'次', reading:'つぎ' }, { text:'世代', reading:'せだい' }, { text:'手渡', reading:'てわた' } ] ],
    bodyRomaji:[ 'katsute nigiwatta matsuri mo, nennen sankasha ga heru ippou datta.', 'dentou ga todaeru no o oshimi, wakamono tachi ga tachiagatta.', 'junbi o kasaneru ni tsurete, machi no kanshin mo sukoshi zutsu takamatta.', 'toujitsu wa sedai o towazu, ooku no hito ga hiroba ni atsumatta.', 'uketsugareta hi wa, mata tsugi no sedai e to tewatasarete iku.' ],
    bodyKo:[ '한때 붐비던 축제도 해마다 참가자가 줄기만 했다.', '전통이 끊기는 것을 아쉬워하며 젊은이들이 나섰다.', '준비를 거듭함에 따라 마을의 관심도 조금씩 높아졌다.', '당일에는 세대를 불문하고 많은 사람이 광장에 모였다.', '이어받은 등불은 다시 다음 세대로 건네져 간다.' ],
    vocabularyIds:["v_n3_744", "v_n4_111", "v_n3_465", "v_n4_1", "v_n3_185", "v_n3_286", "v_n4_809"], grammarIds:["g_n2_133", "g_n3_35"],
    keyVocabularyIds:["v_n3_744", "v_n4_111", "v_n3_465", "v_n4_1", "v_n3_185", "v_n3_286", "v_n4_809"], keyGrammarIds:["g_n2_133", "g_n3_35"],
    bodyHighlights:[ [ { text:'参加者', reading:'さんかしゃ', meaningKo:'참가자', vocabId:'v_n3_744', kind:'vocab' } ], [ { text:'伝統', reading:'でんとう', meaningKo:'전통', vocabId:'v_n4_111', kind:'vocab' }, { text:'若者', reading:'わかもの', meaningKo:'젊은이', vocabId:'v_n3_465', kind:'vocab' } ], [ { text:'準備', reading:'じゅんび', meaningKo:'준비', vocabId:'v_n4_1', kind:'vocab' }, { text:'関心', reading:'かんしん', meaningKo:'관심', vocabId:'v_n3_185', kind:'vocab' } ], [ { text:'世代', reading:'せだい', meaningKo:'세대', vocabId:'v_n3_286', kind:'vocab' }, { text:'広場', reading:'ひろば', meaningKo:'광장', vocabId:'v_n4_809', kind:'vocab' } ], [ { text:'世代', reading:'せだい', meaningKo:'세대', vocabId:'v_n3_286', kind:'vocab' } ] ],
